
// ══════════════════════════════════════
// MODAL LOGIC
// ══════════════════════════════════════
const overlay   = document.getElementById('modalOverlay');
const openBtn   = document.getElementById('openMeldunek');
const closeBtn  = document.getElementById('modalClose');

function filterKwal(q) {
  const sel = document.getElementById('kwalifikacjaSelect');
  const lq = q.toLowerCase();
  Array.from(sel.options).forEach(o => {
    o.style.display = (!lq || o.value==='' || o.text.toLowerCase().includes(lq)) ? '' : 'none';
  });
}
function addInst() {
  const container = document.getElementById('instytucjeContainer');
  const idx = container.querySelectorAll('.inst-block').length;
  const tmpl = container.querySelector('.inst-block').cloneNode(true);
  tmpl.setAttribute('data-idx', idx);
  tmpl.querySelectorAll('input[type=checkbox]').forEach(cb => cb.checked = false);
  tmpl.querySelectorAll('input.inst-dop').forEach(inp => inp.value = '');
  tmpl.querySelector('.inst-select').value = '';
  container.appendChild(tmpl);
}
function removeInst(btn) {
  const container = document.getElementById('instytucjeContainer');
  if (container.querySelectorAll('.inst-block').length <= 1) return;
  btn.closest('.inst-block').remove();
}

function openModal() {
  overlay.classList.add('active');
  document.body.style.overflow = 'hidden';
  const today = new Date().toISOString().split('T')[0];
  if (!document.getElementById('dataMeldunku').value)
    document.getElementById('dataMeldunku').value = today;
  if (!document.getElementById('dataZdarzenia').value)
    document.getElementById('dataZdarzenia').value = today;
}
function closeModal() {
  overlay.classList.remove('active');
  document.body.style.overflow = '';
}

openBtn.addEventListener('click', openModal);
closeBtn.addEventListener('click', closeModal);
overlay.addEventListener('click', e => { if (e.target === overlay) closeModal(); });
document.addEventListener('keydown', e => { if (e.key === 'Escape') closeModal(); });

// ══════════════════════════════════════
// CZCIONKI I ZASOBY (base64)
// ══════════════════════════════════════
const ARIAL_REGULAR_B64 = "";
const ARIAL_BOLD_B64    = "";
  let doc; // zmienna doc dostępna dla pomocniczych funkcji rysowania

  function fmtDate(d){ if(!d)return'___________'; const[y,m,dd]=d.split('-'); return `${dd}.${m}.${y} r.`; }

  // ─── Rysuj komórkę ───
  function cell(x,y,w,h,text,opt){
    const bg=opt.bg!==undefined?opt.bg:WHITE;
    const bold=opt.bold||false, sz=opt.sz||10;
    const va=opt.va||'mid', bord=opt.border!==false;
    doc.setFillColor(...bg); doc.rect(x,y,w,h,'F');
    if(bord){ doc.setDrawColor(...BLACK); doc.setLineWidth(0.18); doc.rect(x,y,w,h,'S'); }
    if(text===null||text===undefined||text==='')return;
    doc.setFont('Arial',bold?'bold':'normal');
    doc.setFontSize(sz); doc.setTextColor(...BLACK);
    const lh=sz*0.3528*1.18, px=1.9, maxW=w-px*2;
    const lines=doc.splitTextToSize(String(text),maxW);
    const th=lines.length*lh;
    const ty2=va==='mid'? y+h/2-th/2+lh*0.78 : y+2.5+lh*0.78;
    doc.text(lines,x+px,ty2);
  }

  // ─── Scalona etykieta kol0 ───
  function label0(x,y,w,h,text){
    doc.setFillColor(...GRAY); doc.setDrawColor(...BLACK);
    doc.setLineWidth(0.18); doc.rect(x,y,w,h,'FD');
    if(!text)return;
    doc.setFont('Arial','normal'); doc.setFontSize(10); doc.setTextColor(...BLACK);
    const lh=10*0.3528*1.18, maxW=w-3.8;
    const lines=doc.splitTextToSize(text,maxW);
    const th=lines.length*lh;
    doc.text(lines,x+1.9,y+h/2-th/2+lh*0.78);
  }

  // ─── Oblicz wysokość komórki ───
  function calcH(text,w,minH,sz){
    if(!text)return minH;
    const lh=(sz||10)*0.3528*1.18, px=1.9*2;
    const lines=doc.splitTextToSize(String(text),w-px);
    return Math.max(minH,lines.length*lh+5);
  }

  // ─── Dane z formularza ───
  function s(v){ return v||''; }

// ─── Dane z formularza ───
const nr = s(document.getElementById('nrMeldunku').value) || '___';
const dataMeldRaw = document.getElementById('dataMeldunku').value;
const ORZEL_B64         = "";

const ARIAL_ITALIC_B64 = "";

function setupDoc(doc) {
  doc.addFileToVFS('LiberationSans-Regular.ttf', ARIAL_REGULAR_B64);
  doc.addFont('LiberationSans-Regular.ttf', 'Arial', 'normal');
  doc.addFileToVFS('LiberationSans-Bold.ttf', ARIAL_BOLD_B64);
  doc.addFont('LiberationSans-Bold.ttf', 'Arial', 'bold');
  doc.addFileToVFS('LiberationSans-Italic.ttf', ARIAL_ITALIC_B64);
  doc.addFont('LiberationSans-Italic.ttf', 'Arial', 'italic');
  doc.setFont('Arial', 'normal');
}

// ══════════════════════════════════════
// GENEROWANIE PDF — MELDUNEK BIEŻĄCY
// ══════════════════════════════════════
document.getElementById('btnGenerujPDF').addEventListener('click', function() {

  const { jsPDF } = window.jspdf;
  doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
  setupDoc(doc);

  // ─── Stałe layoutu ───
  const PAGE_W = 210, PAGE_H = 297;
  const ML = 19.1, MR = 19.1, MT = 25.4, MB = 25.4;
  const CW = PAGE_W - ML - MR;  // 171.8mm
  const COL = [32.4, 40.0, 35.0, 35.0, 37.5];
  const COL_REST = COL[1]+COL[2]+COL[3]+COL[4]; // 147.5mm
  const col12 = COL[1]+COL[2]; // 75mm
  const BLACK=[0,0,0], GRAY=[217,217,217], WHITE=[255,255,255];

  function s(v){ return v||''; }
  // ─── Dane z formularza ───
  const dataMeldRaw=document.getElementById('dataMeldunku').value;
  const rok=dataMeldRaw?dataMeldRaw.split('-')[0]:'2026';
  const dataMeld=fmtDate(dataMeldRaw);
  const miejsc=s(document.getElementById('miejscowosc').value)||'Elbląg';
  const oficer=s(document.getElementById('oficerDyzurny').value)||'_______________';
  const dataZdarz=fmtDate(document.getElementById('dataZdarzenia').value);
  const godz=s(document.getElementById('godzinaZdarzenia').value)||'__:__';
  const miejsce=s(document.getElementById('miejsceZdarzenia').value)||'_______________';
  const kat=s(document.getElementById('kategoriaZdarzenia').value)||'_______________';

  // Dane sprawcy
  const stopien=s(document.getElementById('stopienSprawcy').value)||'';
  const imie=s(document.getElementById('imieSprawcy').value)||'';
  const nazwisko=s(document.getElementById('nazwiskoSprawcy').value)||'';
  const imieOjca=s(document.getElementById('imieOjcaSprawcy').value)||'';
  const jednostka=s(document.getElementById('jednostkaSprawcy').value)||'_______________';
  const miejscJW=s(document.getElementById('miejscowoscJW').value)||'_______________';
  const podleglosc=s(document.getElementById('podlegloscJW').value)||'_______________';

  // Opis + kwalifikacja prawna
  const opis=s(document.getElementById('opisZdarzenia').value)||'_______________';
  const kwalSel=s(document.getElementById('kwalifikacjaSelect').value);
  const kwalDop=s(document.getElementById('kwalDodatkowe').value).trim();
  let kwalStr='';
  if(kwalSel && kwalSel!=='') kwalStr='Kwalifikacja prawna czynu: '+kwalSel;
  if(kwalDop) kwalStr+=(kwalStr?'\n':'Kwalifikacja prawna czynu: ')+kwalDop;
  const opisFull=kwalStr?opis+'\n'+kwalStr:opis;

  // Los sprawcy
  const losArr=Array.from(document.querySelectorAll('input[name="losSprawcy"]:checked')).map(cb=>cb.value);
  const losDod=s(document.getElementById('losDodatkowe').value);
  if(losDod.trim())losArr.push(losDod.trim());
  const los=losArr.length?losArr.join(' '):'_______________';

  // Trzeźwość — dane osobowe + stan
  const sprDane=s(document.getElementById('sprawcaTrzezwosc_dane').value).trim();
  const trzSprStan=s(document.getElementById('trzezwoscSprawcy').value);
  const uczDane=s(document.getElementById('uczestnikTrzezwosc_dane').value).trim();
  const trzUczStan=s(document.getElementById('trzezwoscUczestnikow').value);
  const trzSpr=[sprDane,trzSprStan].filter(Boolean).join('\n')||'---';
  const trzUcz=[uczDane,trzUczStan].filter(Boolean).join('\n')||'---';

  // Czynności — wieloinstytucyjne
  const instBloki=document.querySelectorAll('#instytucjeContainer .inst-block');
  const czynnosciLines=[];
  instBloki.forEach(blok=>{
    const instName=blok.querySelector('.inst-select').value;
    const checked=Array.from(blok.querySelectorAll('.inst-czyn:checked')).map(cb=>'- '+cb.value);
    const dop=blok.querySelector('.inst-dop').value.trim();
    if(instName||checked.length||dop){
      if(instName) czynnosciLines.push(instName+':');
      checked.forEach(c=>czynnosciLines.push(c));
      if(dop) czynnosciLines.push('- '+dop);
    }
  });
  const czyn=czynnosciLines.length?czynnosciLines.join('\n'):'_______________';

  // Środki przymusu
  const przymusArr=Array.from(document.querySelectorAll('input[name="przymus"]:checked')).map(cb=>cb.value);
  const przymusDopTxt=s(document.getElementById('przymusDodatkowe').value).trim();
  let przymus='';
  if(przymusArr.length){
    if(przymusArr[0]==='Nie stosowano środków przymusu bezpośredniego.'){
      przymus='Nie stosowano.';
    } else {
      przymus='Zastosowano: '+przymusArr.join(', ')+'.';
      if(przymusDopTxt) przymus+=' '+przymusDopTxt;
    }
  } else {
    przymus=przymusDopTxt||'Nie stosowano.';
  }

  // Dalsze postępowanie
  const postArr=Array.from(document.querySelectorAll('input[name="postep"]:checked')).map(cb=>cb.value);
  const post=postArr.length?postArr.join(' '):'_______________';

  // Kto prowadzi
  // 'inst' = pierwsza wybrana instytucja (do komórki 'Nazwa instytucji zabezpieczającej')
  const firstBlok=document.querySelector('#instytucjeContainer .inst-block');
  const inst=firstBlok?s(firstBlok.querySelector('.inst-select').value)||'_______________':'_______________';

  const dalszePost=s(document.getElementById('dalszePosto').value);
  const dalszeDop=s(document.getElementById('dalszePostoDop').value).trim();
  const dalsze=dalszeDop||dalszePost||'_______________';

  const uwagi=s(document.getElementById('inneUwagi').value)||'_______________';
  // ════════════════════════════════════════
  // NAGŁÓWEK
  // ════════════════════════════════════════
  // Wymiary z analizy pikselowej wzorca:
  //
  // TEXT BOX (orzeł+jednostka):
  //   pozycja DOCX: x=1.6mm od lewej strony, y=6.9mm od akapitu (para[1])
  //   rozmiar: 85.9 x 33.1mm
  //   RAMKA: widoczna w wzorcu (prostokąt)
  //
  // Pozycje zmierzone w wzorcu (y od góry strony):
  //   DATA:          y=25.4mm (MT), x_prawy=190.9mm (MR)
  //   ORZEŁ góra:    y=33.4mm  (MT+8.0mm)
  //   ORZEŁ h:       9.3mm  (44px / 4.714px/mm)
  //   ODDZIAŁ:       y=49.3mm
  //   ŻANDARMERII:   y=54.2mm
  //   W ELBLĄGU:     y=59.0mm
  //   DSO DYŻURNA:   y=67.8mm,  x=103.3-172.2mm  cx=137.8mm
  //   DSO ŻAND.:     y=73.5mm,  x=102.9-161.3mm  cx=132.1mm
  //   01-163 Warsz.: y=78.3mm,  x=103.1-136.7mm  cx=119.9mm
  //   MILNET-Z:      y=83.0mm,  x=103.1-136.7mm  cx=119.9mm
  //   1. OŻW:        y=95.3mm
  //   meldunek:      y=100.8mm

  // ─── RAMKA i treść lewego bloku ───
  // Box: x=1.6, y=MT-8 (żeby ORZEŁ był na y=MT+8), szer=85.9, wys=33.1mm
  // Ale wzorzec pokazuje ramkę dopasowaną do zawartości - przyjmijmy wymiary z DOCX
  const BOX_X = 1.6;
  const BOX_Y = MT - 8.0;   // y=17.4mm od góry strony
  const BOX_W = 85.9;
  const BOX_H = 43.0;       // do W ELBLĄGU + margines dołu

  // Ramka niewidoczna (transparent) — brak

  // Orzeł: y=33.4mm od góry strony = MT+8mm, h=9.3mm
  const ORZEL_H = 13.0;   // wyświetlamy nieco większy niż 9.3mm dla czytelności
  const ORZEL_Y = MT + 1.0;   // y=26.4mm ≈ góra orła wg pomiaru 33.4mm - korekta
  const BOX_CX  = BOX_X + BOX_W / 2;  // 44.55mm
  const ORZEL_X = BOX_CX - ORZEL_H / 2;
  doc.addImage('data:image/png;base64,'+ORZEL_B64,'PNG', ORZEL_X, ORZEL_Y, ORZEL_H, ORZEL_H);

  // Tekst jednostki: bold 12pt, single spacing
  // ODDZIAŁ y=49.3mm, ŻANDARMERII y=54.2mm, W ELBLĄGU y=59.0mm
  // Odstęp między liniami: ~4.9mm ≈ 12pt * 1.15 = 13.8pt = 4.87mm ✓
  const UNIT_LH = 12 * 0.3528 * 1.15;  // 4.87mm
  doc.setFont('Arial','bold'); doc.setFontSize(12); doc.setTextColor(...BLACK);
  const unitLines = ['ODDZIAŁ','ŻANDARMERII WOJSKOWEJ','W ELBLĄGU'];
  // cx tekstu = 49.6mm (zmierzony), ale rysujemy względem BOX_CX
  let uy = 46.0;   // y pierwszej linii (zmniejszony odstęp od orła)
  for(const ln of unitLines){
    doc.text(ln, BOX_CX, uy, {align:'center'});
    uy += UNIT_LH;
  }

  // ─── DATA — prawa strona, y=MT=25.4mm ───
  doc.setFont('Arial','normal'); doc.setFontSize(12); doc.setTextColor(...BLACK);
  doc.text(`${miejsc}, dn.${dataMeld}`, PAGE_W - MR, MT, {align:'right'});

  // ─── ADRESAT DSO ŻW ───
  // Zmierzone pozycje y i x:
  //   DYŻURNA y=67.8mm  x=103.3-172.2mm  cx=137.8mm
  //   ŻAND.   y=73.5mm  cx=132.1mm
  //   01-163  y=78.3mm  cx=119.9mm
  //   MILNET  y=83.0mm  cx=119.9mm
  // DSO jest wyrównane do środka obszaru x=103-172mm
  // Wyśrodkujemy każdą linię w cx odpowiedniego bloku
  const DSO_CX1 = 137.8;   // DYŻURNA / ŻANDARMERII
  const DSO_CX2 = 119.9;   // 01-163 / MILNET-Z
  const DSO_LH  = 12 * 0.3528 * 1.0;  // single spacing

  // DSO — wyrównane do lewej krawędzi x=103.3mm
  // 'Warszawa' podkreślone, 'MILNET-Z' kursywa (z analizy DOCX runs)
  const DSO_L = 103.3;   // lewa krawędź DSO (zmierzona z wzorca)

  doc.setFont('Arial','bold'); doc.setFontSize(12); doc.setTextColor(...BLACK);
  doc.text('DYŻURNA SŁUŻBA OPERACYJNA', DSO_L, 67.8);
  doc.text('ŻANDARMERII WOJSKOWEJ',     DSO_L, 73.5);

  doc.setFont('Arial','normal');
  doc.text('01-163 ', DSO_L, 78.3);
  // Warszawa — podkreślone
  const w163w = doc.getTextWidth('01-163 ');
  doc.setFont('Arial','normal');
  doc.text('Warszawa', DSO_L + w163w, 78.3);
  // Podkreślenie Warszawa
  const wWarsz = doc.getTextWidth('Warszawa');
  const underY = 78.3 + 0.6;
  doc.setDrawColor(...BLACK); doc.setLineWidth(0.3);
  doc.line(DSO_L + w163w, underY, DSO_L + w163w + wWarsz, underY);

  // MILNET-Z — kursywa (prawdziwy italic Liberation Sans)
  doc.setFont('Arial','italic'); doc.setFontSize(12);
  doc.text('MILNET-Z', DSO_L, 83.0);
  doc.setFont('Arial','normal');

  // ─── TYTUŁ MELDUNKU ───
  // 1. OŻW y=95.3mm (bold), meldunek y=100.8mm (bold, justowany)
  doc.setFont('Arial','bold'); doc.setFontSize(12); doc.setTextColor(...BLACK);
  doc.text('1.  OŻW w Elblągu:', ML, 95.3);
  // Tytuł: "meldunek bieżący nr X/rok: " = normalny, kategoria = bold
  const tLH = 12*0.3528*1.15;
  doc.setFont('Arial','normal');
  const tPre = `meldunek bieżący nr ${nr}/${rok}: `;
  const tPreW = doc.getTextWidth(tPre);
  doc.text(tPre, ML+6, 100.8);
  doc.setFont('Arial','bold');
  const tKat = kat !== '_______________' ? kat+'.' : '_______________';
  const tKatLines = doc.splitTextToSize(tKat, CW-6-tPreW);
  doc.text(tKatLines[0], ML+6+tPreW, 100.8);
  for(let i=1;i<tKatLines.length;i++) doc.text(tKatLines[i], ML+6, 100.8+i*tLH);
  doc.setFont('Arial','normal');

  let ty = 100.8 + Math.max(1, tKatLines.length) * tLH + 5;

  // ════════════════════════════════════════
  // TABELA 5-KOLUMNOWA
  // ════════════════════════════════════════
  const TX = ML;

  function ensureSpace(needed){
    if(ty + needed > PAGE_H - MB - 3){
      doc.addPage(); ty = MT;
    }
  }

  // ── Wiersz 0+1: Data/Godzina/Miejsce ──
  const h0=6.0, h1=12.2;
  ensureSpace(h0+h1);
  cell(TX+COL[0],                           ty,COL[1],     h0,'Data:',             {sz:10,bg:GRAY});
  cell(TX+COL[0]+COL[1],                    ty,COL[2],     h0,'Godzina:',          {sz:10,bg:GRAY});
  cell(TX+COL[0]+COL[1]+COL[2],             ty,COL[3]+COL[4],h0,'Miejsce zdarzenia:',{sz:10,bg:GRAY});
  const rowY01=ty; ty+=h0;
  cell(TX+COL[0],                           ty,COL[1],     h1,dataZdarz,{sz:10,bold:true});
  cell(TX+COL[0]+COL[1],                    ty,COL[2],     h1,godz,     {sz:10,bold:true});
  cell(TX+COL[0]+COL[1]+COL[2],             ty,COL[3]+COL[4],h1,miejsce,{sz:10,bold:true});
  ty+=h1;
  doc.setFillColor(...WHITE); doc.setDrawColor(...BLACK); doc.setLineWidth(0.18);
  doc.rect(TX,rowY01,COL[0],h0+h1,'FD');

  // ── Wiersze 2-6: Dane sprawców ──
  const daneY=ty;
  const h2=7.7,h3=8.4,h4=9.6,h5=9.4,h6=10.3;
  const daneH=h2+h3+h4+h5+h6;
  ensureSpace(daneH);
  cell(TX+COL[0],                       ty,COL[1],h2,'Stopień*/pracownik RON*/osoba cywilna:',{sz:10,bg:GRAY});
  cell(TX+COL[0]+COL[1],                ty,COL[2],h2,'Imię:',      {sz:10,bg:GRAY});
  cell(TX+COL[0]+COL[1]+COL[2],         ty,COL[3],h2,'Nazwisko:',  {sz:10,bg:GRAY});
  cell(TX+COL[0]+COL[1]+COL[2]+COL[3], ty,COL[4],h2,'Imię ojca:', {sz:10,bg:GRAY});
  ty+=h2;
  cell(TX+COL[0],                       ty,COL[1],h3,stopien, {sz:10,bold:true});
  cell(TX+COL[0]+COL[1],                ty,COL[2],h3,imie,    {sz:10,bold:true});
  cell(TX+COL[0]+COL[1]+COL[2],         ty,COL[3],h3,nazwisko,{sz:10,bold:true});
  cell(TX+COL[0]+COL[1]+COL[2]+COL[3], ty,COL[4],h3,imieOjca,{sz:10,bold:true});
  ty+=h3;
  cell(TX+COL[0],ty,COL_REST,h4,'PESEL: _______________',{sz:10,bold:true});
  ty+=h4;
  cell(TX+COL[0],              ty,col12, h5,'Nazwa Jednostki Wojskowej:',{sz:10,bg:GRAY});
  cell(TX+COL[0]+col12,        ty,COL[3],h5,'Miejscowość:',              {sz:10,bg:GRAY});
  cell(TX+COL[0]+col12+COL[3], ty,COL[4],h5,'Podległość JW:',            {sz:10,bg:GRAY});
  ty+=h5;
  cell(TX+COL[0],              ty,col12, h6,jednostka,{sz:10,bold:true});
  cell(TX+COL[0]+col12,        ty,COL[3],h6,miejscJW, {sz:10,bold:true});
  cell(TX+COL[0]+col12+COL[3], ty,COL[4],h6,podleglosc,{sz:10,bold:true});
  ty+=h6;
  label0(TX,daneY,COL[0],daneH,'Dane sprawców:');

  // ── Helper row2 ──
  function row2(labelTxt,valTxt,minH,vaVal){
    const hL=calcH(labelTxt,COL[0],minH,10);
    const hV=calcH(valTxt,COL_REST,minH,10);
    const h=Math.max(hL,hV);
    ensureSpace(h);
    cell(TX,       ty,COL[0],  h,labelTxt,{sz:10,bg:GRAY,va:vaVal||'mid'});
    cell(TX+COL[0],ty,COL_REST,h,valTxt,  {sz:10,va:vaVal||'mid'});
    ty+=h;
  }

  row2('Krótki opis zdarzenia,\n/kwalifikacja prawna czynu/:',opisFull,   29.8,'top');
  row2('Co się stało ze sprawcą /pokrzywdzonym:',              los,    16.2,'mid');

  // ── Trzeźwość ──
  const trzY=ty;
  const h9=10.7,h10=7.9,trzH=h9+h10;
  ensureSpace(trzH);
  cell(TX+COL[0],               ty,COL[1],       h9,'Sprawca:',              {sz:10,bg:GRAY});
  cell(TX+COL[0]+COL[1],        ty,COL[2],       h9,trzSpr,                  {sz:10});
  cell(TX+COL[0]+COL[1]+COL[2], ty,COL[3]+COL[4],h9,'',                     {sz:10});
  ty+=h9;
  cell(TX+COL[0],               ty,COL[1],        h10,'Uczestników zdarzenia:',{sz:10,bg:GRAY});
  cell(TX+COL[0]+COL[1],        ty,COL[2],        h10,trzUcz,                  {sz:10});
  cell(TX+COL[0]+COL[1]+COL[2], ty,COL[3]+COL[4], h10,'',                     {sz:10});
  ty+=h10;
  // Stan trzeźwości — etykieta z mniejszą czcionką (8pt) żeby się zmieściła
  doc.setFillColor(...GRAY); doc.setDrawColor(...BLACK);
  doc.setLineWidth(0.18); doc.rect(TX,trzY,COL[0],trzH,'FD');
  doc.setFont('Arial','normal'); doc.setFontSize(8); doc.setTextColor(...BLACK);
  const trzLabelTxt='Stan trzeźwości /obecność środków odurzających\nw organizmie:';
  const trzLH8=8*0.3528*1.18;
  const trzLines=doc.splitTextToSize(trzLabelTxt,COL[0]-3.8);
  const trzTH=trzLines.length*trzLH8;
  doc.text(trzLines,TX+1.9,trzY+trzH/2-trzTH/2+trzLH8*0.78);
  doc.setFontSize(10);

  row2('Nazwa instytucji zabezpieczającej miejsce zdarzenia:',inst,    24.3,'mid');
  row2('Czynności wykonane na miejscu zdarzenia:',              czyn,   20.2,'top');
  row2('Zastosowane środki przymusu bezpośredniego:',           przymus,20.2,'mid');
  row2('Sposób dalszego postępowania, zakończenia zdarzenia:',  post,   24.3,'top');
  row2('Kto prowadzi dalsze postępowanie:',                     dalsze, 16.2,'mid');
  row2('Inne uwagi:',                                           uwagi,  11.5,'mid');

  // ── Podpis OD ──
  ty+=8; ensureSpace(35);
  const sigX=ML+85.9, sigW=91.9;
  doc.setFont('Arial','bold'); doc.setFontSize(12); doc.setTextColor(...BLACK);
  let sy=ty+4;
  const sigLH=12*0.3528*1.3;
  for(const ln of ['OFICER DYŻURNY','Oddziału Żandarmerii Wojskowej','w Elblągu','/-/ '+oficer]){
    doc.text(ln,sigX+sigW/2,sy,{align:'center'}); sy+=sigLH;
  }

  doc.save('Meldunek_Biezacy_'+nr+'_'+rok+'.pdf');
});

